import{_ as l,o as n,c as i,a2 as e}from"./chunks/framework.Do_4EYrn.js";const u=JSON.parse('{"title":"第 20 章 制度与知识管理","description":"制度与知识管理的难点不是“搜到一段话”，而是确认文件是否有效、内容来自哪里、适用于什么范围。本章只介绍多文档治理的通用方法，不展示真实制度目录或业务资料。 ::: warning 使用边界 WorkBuddy 可以建立索引、抽取条款、比较版本和整理问答…","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 20 章 制度与知识管理/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 20 章 制度与知识管理/index.md","lastUpdated":1784290813000}'),s={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 20 章 制度与知识管理/index.md"};function t(r,a,o,p,h,d){return n(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="第-20-章-制度与知识管理" tabindex="-1">第 20 章 制度与知识管理 <a class="header-anchor" href="#第-20-章-制度与知识管理" aria-label="Permalink to &quot;第 20 章 制度与知识管理&quot;">​</a></h1><p>制度与知识管理的难点不是“搜到一段话”，而是确认文件是否有效、内容来自哪里、适用于什么范围。本章只介绍多文档治理的通用方法，不展示真实制度目录或业务资料。</p><div class="warning custom-block"><p class="custom-block-title">使用边界</p><p>WorkBuddy 可以建立索引、抽取条款、比较版本和整理问答，但不能认定制度效力、替代权威解释或决定具体事项适用哪条规定。</p></div><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>为一批制度、规范、操作说明建立可检索目录。</li><li>比较两个版本的新增、删除和修改内容。</li><li>围绕一个问题查找相关条款并整理出处。</li><li>把重复出现的问题沉淀为知识卡和检查清单。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>形成“找得到、看得懂、能追溯、会更新”的知识资产，同时保留文件效力、适用范围和解释权限的人工判断。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>经授权使用的文件副本或脱敏样本。</li><li>文件名称、发布主体、发布日期、版本和状态。</li><li>本次需要回答的问题与检索范围。</li><li>输出目录、权限范围和更新责任人。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><h3 id="第一步-先建清单-不急着总结" tabindex="-1">第一步：先建清单，不急着总结 <a class="header-anchor" href="#第一步-先建清单-不急着总结" aria-label="Permalink to &quot;第一步：先建清单，不急着总结&quot;">​</a></h3><p>为每份文件记录编号、名称、版本、日期、来源、状态和存放位置。重复文件先标记，不自动删除。</p><h3 id="第二步-建立来源层和知识层" tabindex="-1">第二步：建立来源层和知识层 <a class="header-anchor" href="#第二步-建立来源层和知识层" aria-label="Permalink to &quot;第二步：建立来源层和知识层&quot;">​</a></h3><p>来源层保存原文位置与文件信息；知识层保存摘要、主题、关键词和可复用问答。知识卡必须能回到来源层。</p><h3 id="第三步-按问题检索" tabindex="-1">第三步：按问题检索 <a class="header-anchor" href="#第三步-按问题检索" aria-label="Permalink to &quot;第三步：按问题检索&quot;">​</a></h3><p>让 WorkBuddy 先给出候选条款和出处，再解释它们之间的关系。没有直接依据的推断应单独标记。</p><h3 id="第四步-进行版本比较" tabindex="-1">第四步：进行版本比较 <a class="header-anchor" href="#第四步-进行版本比较" aria-label="Permalink to &quot;第四步：进行版本比较&quot;">​</a></h3><p>比较时区分新增、删除、文字修改和结构移动，并说明可能影响；“是否构成实质变化”由业务或制度管理人员判断。</p><h3 id="第五步-形成更新机制" tabindex="-1">第五步：形成更新机制 <a class="header-anchor" href="#第五步-形成更新机制" aria-label="Permalink to &quot;第五步：形成更新机制&quot;">​</a></h3><p>新文件进入后，更新清单、知识卡和引用关系；旧版本保留历史状态，不静默覆盖。</p><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>假设目录内有三份虚构的《办公用品领用指引》样本，其中一份为旧版。WorkBuddy 可以建立文件清单、比较新旧版本并生成查询卡；文件是否现行有效仍由材料提供者确认。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请对当前工作目录中的文档建立可追溯知识索引。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本次问题：{希望查询或比较的问题}</span></span>
<span class="line"><span>文件范围：{目录或文件名}</span></span>
<span class="line"><span>输出范围：{索引/版本对比/条款检索/知识卡}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请按以下步骤执行：</span></span>
<span class="line"><span>1. 先生成文件清单，记录名称、版本、日期、来源和状态；</span></span>
<span class="line"><span>2. 标记重复、缺页、无法解析和状态不明的文件，不删除原件；</span></span>
<span class="line"><span>3. 提取与问题直接相关的条款并标注文件名、章节和页码；</span></span>
<span class="line"><span>4. 将原文、摘要和你的推断分开；</span></span>
<span class="line"><span>5. 对版本差异按新增、删除、修改、移动分类；</span></span>
<span class="line"><span>6. 输出索引、引用清单、待确认问题和更新建议。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不要判断制度效力，不要把推断写成正式解释。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>文件是否完整、真实、现行有效且允许使用。</li><li>版本和发布主体是否识别正确。</li><li>检索结果是否遗漏关联文件或上位依据。</li><li>摘要是否改变原意，适用范围是否准确。</li><li>对外解释和具体适用结论是否由有权限人员确认。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>文件索引：每份文件有唯一记录和来源位置。</li><li>版本对比表：差异可定位，不只给笼统总结。</li><li>条款证据包：答案、原文、出处和待确认问题分开。</li><li>知识卡：说明适用问题、来源、更新时间和责任边界。</li></ul><h2 id="常见弯路" tabindex="-1">常见弯路 <a class="header-anchor" href="#常见弯路" aria-label="Permalink to &quot;常见弯路&quot;">​</a></h2><ul><li><strong>把搜索结果当答案</strong>：命中关键词不代表适用。必须查看上下文和文件状态。</li><li><strong>只留摘要不留来源</strong>：后续无法复核。所有知识卡都要保留出处。</li><li><strong>新版本直接覆盖旧版</strong>：变化原因和历史依据会丢失。使用版本关系而不是覆盖。</li></ul><h2 id="安全边界" tabindex="-1">安全边界 <a class="header-anchor" href="#安全边界" aria-label="Permalink to &quot;安全边界&quot;">​</a></h2><ul><li>不公开真实制度清单、内部文件目录和业务流程细节。</li><li>不扩大文件访问权限，不把受限材料上传到未批准服务。</li><li>不自动删除重复文件或替换现行版本。</li><li>不把 AI 摘要作为制度原文或权威解释引用。</li></ul><h2 id="可复用资产" tabindex="-1">可复用资产 <a class="header-anchor" href="#可复用资产" aria-label="Permalink to &quot;可复用资产&quot;">​</a></h2><ul><li>文件元数据清单。</li><li>版本对比模板。</li><li>条款证据包模板。</li><li>知识卡模板。</li><li>更新与失效检查清单。</li></ul>`,34)])])}const b=l(s,[["render",t]]);export{u as __pageData,b as default};
